import sailpoint.object.Identity;
import org.apache.log4j.Logger;

Logger log = Logger.getLogger("com.orphancorrelator.workflow.OrphanCorrelationApproval");

log.info("OrphanCorrelationApproval: validate inputs."
         + " nativeIdentity=[" + orcNativeIdentity + "]"
         + " applicationName=[" + orcApplicationName + "]"
         + " identityName=[" + orcIdentityName + "]"
         + " requestedBy=[" + orcRequestedBy + "]");

// When a manager can't be resolved, route the approval to the REQUESTER
// (orcRequestedBy) - a real user who exists in this environment and who
// initiated the request - instead of a hardcoded account. "spadmin" is only
// an absolute last resort if no requester was somehow passed. This keeps the
// plugin portable: it never assumes a client has an account named "spadmin".
String fallbackApprover = (orcRequestedBy != null && orcRequestedBy.length() > 0)
                          ? orcRequestedBy : "spadmin";

if (orcIdentityName == null || orcIdentityName.length() == 0) {
    log.error("OrphanCorrelationApproval: orcIdentityName is null. Routing approval to requester ["
             + fallbackApprover + "].");
    managerName = fallbackApprover;
    return;
}

Identity matched = context.getObjectByName(Identity.class, orcIdentityName);
if (matched == null) {
    log.warn("OrphanCorrelationApproval: identity [" + orcIdentityName
             + "] not found. Routing approval to requester [" + fallbackApprover + "].");
    managerName = fallbackApprover;
    return;
}

Identity manager = matched.getManager();
if (manager == null) {
    log.warn("OrphanCorrelationApproval: identity [" + orcIdentityName
             + "] has no manager. Routing approval to requester [" + fallbackApprover + "].");
    managerName = fallbackApprover;
} else {
    managerName = manager.getName();
    log.info("OrphanCorrelationApproval: resolved manager [" + managerName
             + "] for matched identity [" + orcIdentityName + "].");
}

if (matched != null) { context.decache(matched); }

// Build the account summary via the shared rule (for the result email).
// The on-screen work item uses the same rule from its description Arg.
orcAccountSummary = "(account detail unavailable)";
try {
    sailpoint.object.Rule sumRule = context.getObjectByName(sailpoint.object.Rule.class, "Rule-OrphanAccountSummary");
    if (sumRule != null) {
        java.util.HashMap ra = new java.util.HashMap();
        ra.put("nativeIdentity", orcNativeIdentity);
        ra.put("applicationName", orcApplicationName);
        Object res = context.runRule(sumRule, ra);
        if (res != null && res.toString().length() > 0) { orcAccountSummary = res.toString(); }
    }
} catch (Exception sex) {
    log.warn("OrphanCorrelationApproval: account summary build failed. " + sex.getMessage());
}

import sailpoint.object.*;
import java.util.*;
String base = "Approve correlation of orphan account [" + orcNativeIdentity
              + "] to identity [" + orcIdentityDisplay + "]";
String summary = "";
try {
    Rule sumRule = context.getObjectByName(Rule.class, "Rule-OrphanAccountSummary");
    if (sumRule != null) {
        HashMap ra = new HashMap();
        ra.put("nativeIdentity", orcNativeIdentity);
        ra.put("applicationName", orcApplicationName);
        Object res = context.runRule(sumRule, ra);
        if (res != null) { summary = res.toString(); }
    }
} catch (Exception e) { /* fall back to base description */ }
return (summary != null && summary.length() > 0) ? (base + " -- " + summary) : base;

